const first = $input.all()[0]?.json ?? {};
const triggerMode = Object.keys(first).length > 0 ? 'schedule' : 'manual';
return [{
  json: {
    workflow_name: 'Collect Opportunities',
    triggered_by: triggerMode,
    started_at_utc: new Date().toISOString(),
  },
}];

const root = $('Init Collection Context').first().json;
return [{
  json: {
    source_name: 'We Work Remotely RSS',
    source_catalog_type: 'website',
    config_reference: 'config/n8n/collect-opportunities.sources.json#implementedSources.rss.weworkremotely',
    run_started_at: root.started_at_utc,
    feed_url: $env.COLLECT_RSS_WWR_URL || 'https://weworkremotely.com/remote-jobs.rss',
    opportunity_type: 'vacancy',
    source_type: 'website',
    remote_type: 'remote',
  },
}];

const source = {
  ...$('RSS | We Work Remotely | Source Metadata').first().json,
  ...$('RSS | We Work Remotely | Ensure Source').first().json,
};
const rows = $input.all();
const stripHtml = (value) => String(value || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const normalizeText = (value) => stripHtml(value).slice(0, 12000);
const buildDedupeKey = (row) => [row.title, row.company_name, row.url, row.published_at].filter(Boolean).join(' | ').toLowerCase();

if (rows.length === 1 && rows[0].json && rows[0].json.error) {
  return [{
    json: {
      source_id: source.source_id,
      run_started_at: source.run_started_at,
      fetch_error: rows[0].json.error.message || JSON.stringify(rows[0].json.error),
      opportunities: [],
    },
  }];
}

const opportunities = rows.map(({ json }) => {
  const title = normalizeText(json.title || json.creator || 'Untitled opportunity');
  const description = normalizeText(json.contentSnippet || json.content || json.summary || json.isoDate || '');
  const rawText = normalizeText([json.title, json.contentSnippet, json.content, json.summary].filter(Boolean).join('\n\n'));
  const companyName = normalizeText(json.creator || json['dc:creator'] || '').slice(0, 255) || null;
  const url = json.link || json.guid || null;
  const publishedAt = json.isoDate || json.pubDate || null;
  return {
    external_id: json.guid || json.link || null,
    title,
    description: description || null,
    raw_text: rawText || description || title,
    url,
    company_name: companyName,
    opportunity_type: source.opportunity_type,
    source_type: source.source_type,
    location: null,
    remote_type: source.remote_type,
    budget_min: null,
    budget_max: null,
    currency: null,
    published_at: publishedAt,
    collected_at: new Date().toISOString(),
    status: 'new',
    dedupe_key: buildDedupeKey({ title, company_name: companyName, url, published_at: publishedAt }),
  };
});

return [{
  json: {
    source_id: source.source_id,
    run_started_at: source.run_started_at,
    fetch_error: null,
    opportunities,
  },
}];

