const root = $('Init Collection Context').first().json;
return [{
  json: {
    source_name: 'HeadHunter Automation Search',
    source_catalog_type: 'job_board',
    config_reference: 'config/n8n/collect-opportunities.sources.json#implementedSources.headhunter.automation',
    run_started_at: root.started_at_utc,
    request_url: $env.COLLECT_HH_AUTOMATION_URL || 'https://api.hh.ru/vacancies?text=n8n%20OR%20automation%20OR%20integration%20OR%20workflow&per_page=20&order_by=publication_time',
    opportunity_type: 'vacancy',
    source_type: 'job_board',
  },
}];

const source = {
  ...$('HH | Automation | Source Metadata').first().json,
  ...$('HH | Automation | Ensure Source').first().json,
};
const payload = $input.all()[0]?.json ?? {};
const normalizeText = (value) => String(value || '').replace(/\s+/g, ' ').trim().slice(0, 12000);
const buildDedupeKey = (row) => [row.title, row.company_name, row.url, row.published_at].filter(Boolean).join(' | ').toLowerCase();

if (payload.error) {
  return [{
    json: {
      source_id: source.source_id,
      run_started_at: source.run_started_at,
      fetch_error: payload.error.message || JSON.stringify(payload.error),
      opportunities: [],
    },
  }];
}

const items = Array.isArray(payload.items) ? payload.items : [];
const opportunities = items.map((item) => {
  const description = normalizeText([item.snippet?.requirement, item.snippet?.responsibility].filter(Boolean).join(' '));
  const rawText = JSON.stringify(item);
  const title = normalizeText(item.name || 'Untitled vacancy');
  const companyName = normalizeText(item.employer?.name || '').slice(0, 255) || null;
  const location = normalizeText(item.area?.name || '') || null;
  const remoteType = item.schedule?.id === 'remote' ? 'remote' : (item.work_format?.includes?.('REMOTE') ? 'remote' : 'unknown');
  return {
    external_id: item.id || null,
    title,
    description: description || null,
    raw_text: rawText,
    url: item.alternate_url || item.url || null,
    company_name: companyName,
    opportunity_type: source.opportunity_type,
    source_type: source.source_type,
    location,
    remote_type: remoteType,
    budget_min: item.salary?.from ?? null,
    budget_max: item.salary?.to ?? null,
    currency: item.salary?.currency ?? null,
    published_at: item.published_at || null,
    collected_at: new Date().toISOString(),
    status: 'new',
    dedupe_key: buildDedupeKey({ title, company_name: companyName, url: item.alternate_url || item.url || null, published_at: item.published_at || null }),
  };
});

return [{
  json: {
    source_id: source.source_id,
    run_started_at: source.run_started_at,
    fetch_error: null,
    opportunities,
  },
}];

